#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    cin >> N;

    vector<vector<int>> photos(5, vector<int>(N));
    for (int i = 0; i < 5; i++) {
        for (int j = 0; j < N; j++) {
            cin >> photos[i][j];
        }
    }

    // For each cow, collect the positions (indices) it appears in across the 5 photos
    vector<vector<int>> pos_of(N + 1);
    for (int p = 0; p < 5; p++) {
        for (int idx = 0; idx < N; idx++) {
            int cow = photos[p][idx];
            pos_of[cow].push_back(idx);
        }
    }

    // Determine the original order: sort cows by the median (or majority) of their positions
    // Since at most 2 photos have this cow moved, the other >=3 photos show the correct position.
    // So we can sort by median of the 5 positions (equivalently, sort by the middle element after sorting).
    vector<pair<int, int>> cow_pos; // (original_position, cow_id)
    for (int cow = 1; cow <= N; cow++) {
        vector<int> &pos = pos_of[cow];
        sort(pos.begin(), pos.end());
        // The median (3rd smallest out of 5) gives the original position
        cow_pos.emplace_back(pos[2], cow);
    }

    sort(cow_pos.begin(), cow_pos.end());

    for (int i = 0; i < N; i++) {
        if (i) cout << ' ';
        cout << cow_pos[i].second;
    }
    cout << '\n';

    return 0;
}
